191.         public ActionResult Delete(int? id)
192.         {
193.             if (id == null)
194.             {
195.                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
196.             }
197.             Student student = db.Students.Find(id);
198.             if (student == null)
199.             {
