using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public static class TestHelpers
{
    public static SchoolContext CreateInMemoryContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;

        var context = new SchoolContext(options);
        return context;
    }

    public static SchoolContext CreateSeededContext()
    {
        var context = CreateInMemoryContext();
        SeedData(context);
        return context;
    }

    public static void SeedData(SchoolContext context)
    {
        var departments = new[]
        {
            new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 1 },
            new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 2 },
            new Department { DepartmentID = 3, Name = "Engineering", Budget = 550000, StartDate = DateTime.Parse("2007-09-01") }
        };
        context.Departments.AddRange(departments);

        var instructors = new[]
        {
            new Instructor { ID = 1, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11"), CourseAssignments = new List<CourseAssignment>() },
            new Instructor { ID = 2, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06"), CourseAssignments = new List<CourseAssignment>() },
            new Instructor { ID = 3, FirstMidName = "Roger", LastName = "Harui", HireDate = DateTime.Parse("1998-07-01"), CourseAssignments = new List<CourseAssignment>() }
        };
        context.Instructors.AddRange(instructors);

        var courses = new[]
        {
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 3 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 },
            new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 2 }
        };
        context.Courses.AddRange(courses);

        var students = new[]
        {
            new Student { ID = 10, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { ID = 11, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { ID = 12, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
            new Student { ID = 13, FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { ID = 14, FirstMidName = "Yan", LastName = "Li", EnrollmentDate = DateTime.Parse("2012-09-01") }
        };
        context.Students.AddRange(students);

        var enrollments = new[]
        {
            new Enrollment { EnrollmentID = 1, StudentID = 10, CourseID = 1050, Grade = Grade.A },
            new Enrollment { EnrollmentID = 2, StudentID = 10, CourseID = 4022, Grade = Grade.C },
            new Enrollment { EnrollmentID = 3, StudentID = 11, CourseID = 4041, Grade = Grade.B }
        };
        context.Enrollments.AddRange(enrollments);

        context.SaveChanges();
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain any pre-existing notifications from other tests (shared static queue)
        while (_service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        _service.Dispose();
    }

    [Fact]
    public void SendNotification_EnqueuesNotification_CanBeReceived()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("John Doe", notification.Message);
        Assert.Equal("admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _service.SendNotification("Course", "101", "Math 101", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_SimplifiedOverload_Works()
    {
        _service.SendNotification("Department", "5", EntityOperation.DELETE);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Department", notification.EntityType);
        Assert.Equal("5", notification.EntityId);
        Assert.Equal("DELETE", notification.Operation);
        Assert.Contains("Department (ID: 5)", notification.Message);
    }

    [Fact]
    public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
    {
        var notification = _service.ReceiveNotification();

        Assert.Null(notification);
    }

    [Fact]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.Equal("New Student 'John Doe' has been created", notification!.Message);
    }

    [Fact]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.Equal("Course 'Chemistry' has been updated", notification!.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

        var notification = _service.ReceiveNotification();

        Assert.Equal("Department 'Engineering' has been deleted", notification!.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Instructor", "42", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.Equal("New Instructor (ID: 42) has been created", notification!.Message);
    }

    [Fact]
    public void SendNotification_MultipleNotifications_ReceivedInOrder()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        _service.SendNotification("Course", "2", EntityOperation.UPDATE);
        _service.SendNotification("Department", "3", EntityOperation.DELETE);

        var n1 = _service.ReceiveNotification();
        var n2 = _service.ReceiveNotification();
        var n3 = _service.ReceiveNotification();

        Assert.Equal("Student", n1!.EntityType);
        Assert.Equal("Course", n2!.EntityType);
        Assert.Equal("Department", n3!.EntityType);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var notification = _service.ReceiveNotification();

        Assert.InRange(notification!.CreatedAt, before, after);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op but should not throw
        var exception = Record.Exception(() => _service.MarkAsRead(1));

        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();

        var exception = Record.Exception(() => service.Dispose());

        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_WithNullDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "5", null!, EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.Contains("ID: 5", notification!.Message);
    }

    [Fact]
    public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "5", "", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.Contains("ID: 5", notification!.Message);
    }

    [Fact]
    public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "5", "   ", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.Contains("ID: 5", notification!.Message);
    }
}

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsPageIndexCorrectly()
    {
        var items = new List<string> { "a", "b", "c" };

        var list = new PaginatedList<string>(items, 10, 2, 3);

        Assert.Equal(2, list.PageIndex);
    }

    [Fact]
    public void Constructor_CalculatesTotalPagesCorrectly()
    {
        var items = new List<string> { "a", "b", "c" };

        var list = new PaginatedList<string>(items, 10, 1, 3);

        Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
    }

    [Fact]
    public void Constructor_TotalPagesRoundsUp()
    {
        var items = new List<string> { "a" };

        var list = new PaginatedList<string>(items, 7, 1, 3);

        Assert.Equal(3, list.TotalPages); // ceil(7/3) = 3
    }

    [Fact]
    public void Constructor_ExactDivision_CorrectTotalPages()
    {
        var items = new List<string> { "a", "b" };

        var list = new PaginatedList<string>(items, 6, 1, 3);

        Assert.Equal(2, list.TotalPages); // ceil(6/3) = 2
    }

    [Fact]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<string> { "a", "b", "c" };

        var list = new PaginatedList<string>(items, 10, 1, 5);

        Assert.Equal(3, list.Count);
        Assert.Contains("a", list);
        Assert.Contains("b", list);
        Assert.Contains("c", list);
    }

    [Fact]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var items = new List<string> { "a" };

        var list = new PaginatedList<string>(items, 10, 1, 5);

        Assert.False(list.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var items = new List<string> { "a" };

        var list = new PaginatedList<string>(items, 10, 2, 5);

        Assert.True(list.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var items = new List<string> { "a" };

        var list = new PaginatedList<string>(items, 10, 2, 5); // TotalPages = 2

        Assert.False(list.HasNextPage);
    }

    [Fact]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        var items = new List<string> { "a" };

        var list = new PaginatedList<string>(items, 10, 1, 5); // TotalPages = 2

        Assert.True(list.HasNextPage);
    }

    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 5);

        Assert.Equal(2, result.PageIndex);
        Assert.Equal(4, result.TotalPages);
        Assert.Equal(5, result.Count);
        Assert.Equal(6, result[0]);
        Assert.Equal(10, result[4]);
    }

    [Fact]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        var source = Enumerable.Range(1, 15).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(5, result.Count);
        Assert.Equal(1, result[0]);
    }

    [Fact]
    public void Create_LastPage_MayHaveFewerItems()
    {
        var source = Enumerable.Range(1, 13).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 5);

        Assert.Equal(3, result.Count); // 13 - 10 = 3 items on last page
    }

    [Fact]
    public void Create_SingleItem_SinglePage()
    {
        var source = new[] { 42 }.AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(1, result.TotalPages);
        Assert.Single(result);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
    }
}

