using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain any pre-existing notifications from other tests (shared static queue)
        while (_service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        _service.Dispose();
    }

    [Fact]
    public void SendNotification_EnqueuesNotification_CanBeReceived()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("John Doe", notification.Message);
        Assert.Equal("admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _service.SendNotification("Course", "101", "Math 101", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_SimplifiedOverload_Works()
    {
        _service.SendNotification("Department", "5", EntityOperation.DELETE);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Department", notification.EntityType);
        Assert.Equal("5", notification.EntityId);
        Assert.Equal("DELETE", notification.Operation);
        Assert.Contains("Department (ID: 5)", notification.Message);
    }

    [Fact]
    public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
    {
        var notification = _service.ReceiveNotification();

        Assert.Null(notification);
    }

    [Fact]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.Equal("New Student 'John Doe' has been created", notification!.Message);
    }

    [Fact]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.Equal("Course 'Chemistry' has been updated", notification!.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

        var notification = _service.ReceiveNotification();

        Assert.Equal("Department 'Engineering' has been deleted", notification!.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Instructor", "42", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.Equal("New Instructor (ID: 42) has been created", notification!.Message);
    }

    [Fact]
    public void SendNotification_MultipleNotifications_ReceivedInOrder()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        _service.SendNotification("Course", "2", EntityOperation.UPDATE);
        _service.SendNotification("Department", "3", EntityOperation.DELETE);

        var n1 = _service.ReceiveNotification();
        var n2 = _service.ReceiveNotification();
        var n3 = _service.ReceiveNotification();

        Assert.Equal("Student", n1!.EntityType);
        Assert.Equal("Course", n2!.EntityType);
        Assert.Equal("Department", n3!.EntityType);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var notification = _service.ReceiveNotification();

        Assert.InRange(notification!.CreatedAt, before, after);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op but should not throw
        var exception = Record.Exception(() => _service.MarkAsRead(1));

        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();

        var exception = Record.Exception(() => service.Dispose());

        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_WithNullDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "5", null!, EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.Contains("ID: 5", notification!.Message);
    }

    [Fact]
    public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "5", "", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.Contains("ID: 5", notification!.Message);
    }

    [Fact]
    public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "5", "   ", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.Contains("ID: 5", notification!.Message);
    }
}

