        var retrieved = context.Instructors.First(i => i.LastName == "Smith");
        Assert.Equal("Jane", retrieved.FirstMidName);
    }

    [Fact]
    public void Context_CanAddEnrollmentWithRelationships()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var student = new Student { FirstMidName = "A", LastName = "B", EnrollmentDate = DateTime.Now };
        var dept = new Department { DepartmentID = 1, Name = "Dept", Budget = 1000, StartDate = DateTime.Now };
        var course = new Course { CourseID = 100, Title = "Course", Credits = 3, DepartmentID = 1 };
        context.Departments.Add(dept);
        context.Students.Add(student);
        context.Courses.Add(course);
        context.SaveChanges();

        var enrollment = new Enrollment { StudentID = student.ID, CourseID = 100, Grade = Grade.B };
        context.Enrollments.Add(enrollment);
        context.SaveChanges();

        var retrieved = context.Enrollments.Include(e => e.Student).Include(e => e.Course)
            .First(e => e.StudentID == student.ID);
