    private static Mock<IFormFile> CreateMockFormFile(string fileName, long length)
    {
        var fileMock = new Mock<IFormFile>();
        var memoryStream = new MemoryStream(new byte[length]);
        fileMock.Setup(f => f.FileName).Returns(fileName);
        fileMock.Setup(f => f.Length).Returns(length);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
            .Callback<Stream>(s => memoryStream.CopyTo(s));
        fileMock.Setup(f => f.OpenReadStream()).Returns(memoryStream);
        return fileMock;
    }
