using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _mockEnv;
    private readonly Mock<ILogger<CoursesController>> _mockLogger;

    public CoursesControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockEnv.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _mockEnv.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _mockLogger = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsViewWithAllCourses()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<IEnumerable<Course>>(result.Model);
        Assert.Equal(3, model.Count());
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Details(1050) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Chemistry", course.Title);
        Assert.Equal(3, course.DepartmentID);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithDepartmentSelectList()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
        Assert.IsType<Course>(result.Model);
    }

    [Fact]
    public void Create_Post_ValidCourse_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 4,
            DepartmentID = 1
        };

        var result = _controller.Create(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Create_Post_ValidCourse_SavesInDatabase()
    {
        var course = new Course
        {
            CourseID = 8888,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = 2
        };

        _controller.Create(course, null!);

        Assert.NotNull(_context.Courses.Find(8888));
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 7777, Credits = 3, DepartmentID = 1 };

        var result = _controller.Create(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
    {
        var course = new Course
        {
            CourseID = 5555,
            Title = "Course with Image",
            Credits = 3,
            DepartmentID = 1
        };
        var fileMock = CreateMockFormFile("test.exe", 1024);

        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_FileTooLarge_ReturnsViewWithError()
    {
        var course = new Course
        {
            CourseID = 5556,
            Title = "Course with Large Image",
            Credits = 3,
            DepartmentID = 1
        };
        var fileMock = CreateMockFormFile("test.jpg", 6 * 1024 * 1024);

        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_ValidImage_SavesFile()
    {
        var course = new Course
        {
            CourseID = 5557,
            Title = "Course with Valid Image",
            Credits = 3,
            DepartmentID = 1
        };
        var fileMock = CreateMockFormFile("test.jpg", 1024);

        var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        var savedCourse = _context.Courses.Find(5557);
        Assert.NotNull(savedCourse!.TeachingMaterialImagePath);
        Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsView()
    {
        var result = _controller.Edit(1050) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal(1050, course.CourseID);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Post_ValidCourse_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Updated Chemistry",
            Credits = 4,
            DepartmentID = 3
        };
        // Detach tracked entity
        var tracked = _context.Courses.Find(1050);
        _context.Entry(tracked!).State = EntityState.Detached;

        var result = _controller.Edit(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1050, Credits = 3, DepartmentID = 3 };

        var result = _controller.Edit(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_InvalidFileExtension_ReturnsViewWithError()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 3
        };
        // Detach tracked entity
        var tracked = _context.Courses.Find(1050);
        _context.Entry(tracked!).State = EntityState.Detached;

        var fileMock = CreateMockFormFile("malware.pdf", 1024);

        var result = _controller.Edit(course, fileMock.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsView()
    {
        var result = _controller.Delete(1050) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal(1050, course.CourseID);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void DeleteConfirmed_RemovesCourse_RedirectsToIndex()
    {
        var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Null(_context.Courses.Find(1050));
    }

    private static Mock<IFormFile> CreateMockFormFile(string fileName, long length)
    {
        var fileMock = new Mock<IFormFile>();
        var memoryStream = new MemoryStream(new byte[length]);
        fileMock.Setup(f => f.FileName).Returns(fileName);
        fileMock.Setup(f => f.Length).Returns(length);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
            .Callback<Stream>(s => memoryStream.CopyTo(s));
        fileMock.Setup(f => f.OpenReadStream()).Returns(memoryStream);
        return fileMock;
    }
}

