using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests.Models;

public class ModelTests
{
    [Fact]
    public void Person_FullName_ReturnsLastNameCommaFirstName()
    {
        var student = new Student { FirstMidName = "John", LastName = "Doe" };

        Assert.Equal("Doe, John", student.FullName);
    }

    [Fact]
    public void Student_InheritsFromPerson()
    {
        var student = new Student();

        Assert.IsAssignableFrom<Person>(student);
    }

    [Fact]
    public void Instructor_InheritsFromPerson()
    {
        var instructor = new Instructor();

        Assert.IsAssignableFrom<Person>(instructor);
    }

    [Fact]
    public void Instructor_FullName_ReturnsLastNameCommaFirstName()
    {
        var instructor = new Instructor { FirstMidName = "Kim", LastName = "Abercrombie" };

        Assert.Equal("Abercrombie, Kim", instructor.FullName);
    }

    [Fact]
    public void Student_EnrollmentDate_CanBeSet()
    {
        var date = new DateTime(2023, 9, 1);
        var student = new Student { EnrollmentDate = date };

        Assert.Equal(date, student.EnrollmentDate);
    }

    [Fact]
    public void Instructor_HireDate_CanBeSet()
    {
        var date = new DateTime(2020, 1, 15);
        var instructor = new Instructor { HireDate = date };

        Assert.Equal(date, instructor.HireDate);
    }

    [Fact]
    public void Course_Properties_SetCorrectly()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/images/chem.jpg"
        };

        Assert.Equal(1050, course.CourseID);
        Assert.Equal("Chemistry", course.Title);
        Assert.Equal(3, course.Credits);
        Assert.Equal(1, course.DepartmentID);
        Assert.Equal("/images/chem.jpg", course.TeachingMaterialImagePath);
    }

    [Fact]
    public void Department_Properties_SetCorrectly()
    {
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 500000,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = 1
        };

        Assert.Equal(1, dept.DepartmentID);
        Assert.Equal("Engineering", dept.Name);
        Assert.Equal(500000, dept.Budget);
        Assert.Equal(new DateTime(2007, 9, 1), dept.StartDate);
        Assert.Equal(1, dept.InstructorID);
    }

    [Fact]
    public void Enrollment_Properties_SetCorrectly()
    {
        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 1050,
            StudentID = 10,
            Grade = Grade.A
        };

        Assert.Equal(1, enrollment.EnrollmentID);
        Assert.Equal(1050, enrollment.CourseID);
        Assert.Equal(10, enrollment.StudentID);
        Assert.Equal(Grade.A, enrollment.Grade);
    }

    [Fact]
    public void Enrollment_Grade_CanBeNull()
    {
        var enrollment = new Enrollment { EnrollmentID = 1, CourseID = 1, StudentID = 1 };

        Assert.Null(enrollment.Grade);
    }

    [Fact]
    public void CourseAssignment_Properties_SetCorrectly()
    {
        var assignment = new CourseAssignment
        {
            InstructorID = 1,
            CourseID = 1050
        };

        Assert.Equal(1, assignment.InstructorID);
        Assert.Equal(1050, assignment.CourseID);
    }

    [Fact]
    public void OfficeAssignment_Properties_SetCorrectly()
    {
        var office = new OfficeAssignment
        {
            InstructorID = 1,
            Location = "Room 301"
        };

        Assert.Equal(1, office.InstructorID);
        Assert.Equal("Room 301", office.Location);
    }

    [Fact]
    public void Notification_Properties_SetCorrectly()
    {
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "10",
            Operation = "CREATE",
            Message = "New Student has been created",
            CreatedAt = DateTime.Now,
            CreatedBy = "admin",
            IsRead = false,
            ReadAt = null
        };

        Assert.Equal(1, notification.Id);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("10", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("created", notification.Message);
        Assert.Equal("admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
        Assert.Null(notification.ReadAt);
    }

    [Fact]
    public void Notification_ReadAt_CanBeSet()
    {
        var readTime = DateTime.Now;
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Course",
            EntityId = "1",
            Operation = "UPDATE",
            Message = "Updated",
            CreatedAt = DateTime.Now,
            IsRead = true,
            ReadAt = readTime
        };

        Assert.True(notification.IsRead);
        Assert.Equal(readTime, notification.ReadAt);
    }

    [Fact]
    public void EntityOperation_HasExpectedValues()
    {
        Assert.Equal(0, (int)EntityOperation.CREATE);
        Assert.Equal(1, (int)EntityOperation.UPDATE);
        Assert.Equal(2, (int)EntityOperation.DELETE);
    }

    [Fact]
    public void Grade_HasExpectedValues()
    {
        Assert.Equal(0, (int)Grade.A);
        Assert.Equal(1, (int)Grade.B);
        Assert.Equal(2, (int)Grade.C);
        Assert.Equal(3, (int)Grade.D);
        Assert.Equal(4, (int)Grade.F);
    }

    [Fact]
    public void EnrollmentDateGroup_Properties_SetCorrectly()
    {
        var group = new EnrollmentDateGroup
        {
            EnrollmentDate = new DateTime(2023, 9, 1),
            StudentCount = 5
        };

        Assert.Equal(new DateTime(2023, 9, 1), group.EnrollmentDate);
        Assert.Equal(5, group.StudentCount);
    }

    [Fact]
    public void EnrollmentDateGroup_EnrollmentDate_CanBeNull()
    {
        var group = new EnrollmentDateGroup { StudentCount = 3 };

        Assert.Null(group.EnrollmentDate);
    }

    [Fact]
    public void AssignedCourseData_Properties_SetCorrectly()
    {
        var data = new AssignedCourseData
        {
            CourseID = 1050,
            Title = "Chemistry",
            Assigned = true
        };

        Assert.Equal(1050, data.CourseID);
        Assert.Equal("Chemistry", data.Title);
        Assert.True(data.Assigned);
    }

    [Fact]
    public void InstructorIndexData_Properties_CanBeSet()
    {
        var data = new InstructorIndexData
        {
            Instructors = new List<Instructor>(),
            Courses = new List<Course>(),
            Enrollments = new List<Enrollment>()
        };

        Assert.NotNull(data.Instructors);
        Assert.NotNull(data.Courses);
        Assert.NotNull(data.Enrollments);
    }

    [Fact]
    public void Department_InstructorID_CanBeNull()
    {
        var dept = new Department { Name = "Test", Budget = 100 };

        Assert.Null(dept.InstructorID);
    }

    [Fact]
    public void Student_Enrollments_CanBeInitialized()
    {
        var student = new Student { Enrollments = new List<Enrollment>() };

        Assert.NotNull(student.Enrollments);
        Assert.Empty(student.Enrollments);
    }

    [Fact]
    public void Instructor_CourseAssignments_CanBeInitialized()
    {
        var instructor = new Instructor { CourseAssignments = new List<CourseAssignment>() };

        Assert.NotNull(instructor.CourseAssignments);
        Assert.Empty(instructor.CourseAssignments);
    }
}

