using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public class SchoolContextTests
{
    [Fact]
    public void Context_CanAddAndRetrieveStudent()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        context.Students.Add(student);
        context.SaveChanges();

        var retrieved = context.Students.First(s => s.LastName == "Student");
        Assert.Equal("Test", retrieved.FirstMidName);
    }

    [Fact]
    public void Context_CanAddAndRetrieveCourse()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var dept = new Department { DepartmentID = 1, Name = "Science", Budget = 100000, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        var course = new Course { CourseID = 2001, Title = "Physics", Credits = 4, DepartmentID = 1 };

        context.Courses.Add(course);
        context.SaveChanges();

        var retrieved = context.Courses.Find(2001);
        Assert.NotNull(retrieved);
        Assert.Equal("Physics", retrieved.Title);
    }

    [Fact]
    public void Context_CanAddAndRetrieveDepartment()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var dept = new Department
        {
            Name = "History",
            Budget = 200000,
            StartDate = DateTime.Parse("2005-09-01")
        };

        context.Departments.Add(dept);
        context.SaveChanges();

        var retrieved = context.Departments.First(d => d.Name == "History");
        Assert.Equal(200000, retrieved.Budget);
    }

    [Fact]
    public void Context_CanAddAndRetrieveInstructor()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var instructor = new Instructor
        {
            FirstMidName = "Jane",
            LastName = "Smith",
            HireDate = DateTime.Parse("2010-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };

        context.Instructors.Add(instructor);
        context.SaveChanges();

        var retrieved = context.Instructors.First(i => i.LastName == "Smith");
        Assert.Equal("Jane", retrieved.FirstMidName);
    }

    [Fact]
    public void Context_CanAddEnrollmentWithRelationships()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var student = new Student { FirstMidName = "A", LastName = "B", EnrollmentDate = DateTime.Now };
        var dept = new Department { DepartmentID = 1, Name = "Dept", Budget = 1000, StartDate = DateTime.Now };
        var course = new Course { CourseID = 100, Title = "Course", Credits = 3, DepartmentID = 1 };
        context.Departments.Add(dept);
        context.Students.Add(student);
        context.Courses.Add(course);
        context.SaveChanges();

        var enrollment = new Enrollment { StudentID = student.ID, CourseID = 100, Grade = Grade.B };
        context.Enrollments.Add(enrollment);
        context.SaveChanges();

        var retrieved = context.Enrollments.Include(e => e.Student).Include(e => e.Course)
            .First(e => e.StudentID == student.ID);
        Assert.Equal(Grade.B, retrieved.Grade);
        Assert.Equal("B", retrieved.Student.LastName);
        Assert.Equal("Course", retrieved.Course.Title);
    }

    [Fact]
    public void Context_CanCreateCourseAssignment()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var instructor = new Instructor { ID = 1, FirstMidName = "A", LastName = "B", HireDate = DateTime.Now, CourseAssignments = new List<CourseAssignment>() };
        var dept = new Department { DepartmentID = 1, Name = "Dept", Budget = 1000, StartDate = DateTime.Now };
        var course = new Course { CourseID = 200, Title = "Course", Credits = 3, DepartmentID = 1 };
        context.Departments.Add(dept);
        context.Instructors.Add(instructor);
        context.Courses.Add(course);
        context.SaveChanges();

        context.CourseAssignments.Add(new CourseAssignment { InstructorID = 1, CourseID = 200 });
        context.SaveChanges();

        var assignment = context.CourseAssignments.First(ca => ca.InstructorID == 1 && ca.CourseID == 200);
        Assert.NotNull(assignment);
    }

    [Fact]
    public void Context_CanCreateOfficeAssignment()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var instructor = new Instructor { ID = 1, FirstMidName = "A", LastName = "B", HireDate = DateTime.Now, CourseAssignments = new List<CourseAssignment>() };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 1, Location = "Room 42" });
        context.SaveChanges();

        var office = context.OfficeAssignments.Find(1);
        Assert.NotNull(office);
        Assert.Equal("Room 42", office.Location);
    }

    [Fact]
    public void Context_StudentDeleteCascadesEnrollments()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        TestHelpers.SeedData(context);

        var student = context.Students.Find(10);
        context.Students.Remove(student!);
        context.SaveChanges();

        Assert.Empty(context.Enrollments.Where(e => e.StudentID == 10));
    }

    [Fact]
    public void Context_DbSetsAreNotNull()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        Assert.NotNull(context.Courses);
        Assert.NotNull(context.Enrollments);
        Assert.NotNull(context.Departments);
        Assert.NotNull(context.OfficeAssignments);
        Assert.NotNull(context.CourseAssignments);
        Assert.NotNull(context.People);
        Assert.NotNull(context.Students);
        Assert.NotNull(context.Instructors);
        Assert.NotNull(context.Notifications);
    }
}

